package com.hr.data;

import com.hr.model.Employee;
import com.hr.model.PerformanceReview;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.stream.Collectors;

public class EmployeeDataStore {
    private static EmployeeDataStore instance;
    private final Map<String, Employee> employees = new ConcurrentHashMap<>();
    private final Map<String, List<PerformanceReview>> reviews = new ConcurrentHashMap<>();

    private EmployeeDataStore() {
        initSampleData();
    }

    public static synchronized EmployeeDataStore getInstance() {
        if (instance == null) {
            instance = new EmployeeDataStore();
        }
        return instance;
    }

    private void initSampleData() {
        employees.put("EMP001", new Employee("EMP001", "John", "Doe", "Engineering",
                new BigDecimal("85000.00"), "ACTIVE", LocalDate.of(2020, 3, 15)));
        employees.put("EMP002", new Employee("EMP002", "Jane", "Smith", "Marketing",
                new BigDecimal("72000.00"), "ACTIVE", LocalDate.of(2019, 7, 1)));
        employees.put("EMP003", new Employee("EMP003", "Bob", "Johnson", "Finance",
                new BigDecimal("90000.00"), "ACTIVE", LocalDate.of(2018, 1, 10)));
        employees.put("EMP004", new Employee("EMP004", "Alice", "Williams", "Engineering",
                new BigDecimal("95000.00"), "ACTIVE", LocalDate.of(2017, 11, 20)));
        employees.put("EMP005", new Employee("EMP005", "Charlie", "Brown", "HR",
                new BigDecimal("68000.00"), "ACTIVE", LocalDate.of(2021, 5, 3)));
    }

    public Employee getEmployee(String employeeId) {
        return employees.get(employeeId);
    }

    public void updateEmployee(Employee employee) {
        employees.put(employee.getEmployeeId(), employee);
    }

    public void addReview(String employeeId, PerformanceReview review) {
        reviews.computeIfAbsent(employeeId, k -> new ArrayList<>()).add(review);
    }

    public List<PerformanceReview> getReviews(String employeeId) {
        return reviews.getOrDefault(employeeId, new ArrayList<>());
    }

    public List<Employee> getAllEmployees() {
        return new ArrayList<>(employees.values());
    }

    public List<Employee> getActiveEmployees() {
        return employees.values().stream()
                .filter(e -> "ACTIVE".equals(e.getStatus()))
                .collect(Collectors.toList());
    }
}

