package com.hr.audit;

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.logging.Logger;

public class AuditLogger {
    private static final Logger logger = Logger.getLogger(AuditLogger.class.getName());
    private static final DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");

    public static void logAction(String action, String employeeId, String performedBy, String details) {
        String timestamp = LocalDateTime.now().format(formatter);
        String auditEntry = String.format("[AUDIT] %s | Action: %s | EmployeeId: %s | PerformedBy: %s | Details: %s",
                timestamp, action, employeeId, performedBy, details);
        logger.info(auditEntry);
    }

    public static void logSecurityEvent(String event, String details) {
        String timestamp = LocalDateTime.now().format(formatter);
        String auditEntry = String.format("[SECURITY] %s | Event: %s | Details: %s",
                timestamp, event, details);
        logger.warning(auditEntry);
    }
}

