package com.hr.validation;

import com.hr.exception.EmployeeServiceException;

import java.math.BigDecimal;
import java.util.Arrays;
import java.util.List;
import java.util.regex.Pattern;

public class InputValidator {

    private static final Pattern EMPLOYEE_ID_PATTERN = Pattern.compile("^EMP\\d{3,6}$");
    private static final Pattern NAME_PATTERN = Pattern.compile("^[a-zA-Z\\s\\-']{1,100}$");
    private static final List<String> VALID_RATINGS = Arrays.asList(
            "EXCELLENT", "GOOD", "SATISFACTORY", "NEEDS_IMPROVEMENT", "UNSATISFACTORY");
    private static final List<String> VALID_TERMINATION_REASONS = Arrays.asList(
            "VOLUNTARY_RESIGNATION", "LAYOFF", "TERMINATION_FOR_CAUSE",
            "RETIREMENT", "CONTRACT_END", "MUTUAL_AGREEMENT");
    private static final BigDecimal MIN_SALARY = new BigDecimal("15000.00");
    private static final BigDecimal MAX_SALARY = new BigDecimal("500000.00");
    private static final int MAX_NOTES_LENGTH = 2000;

    public static void validateEmployeeId(String employeeId) throws EmployeeServiceException {
        if (employeeId == null || employeeId.trim().isEmpty()) {
            throw new EmployeeServiceException("Employee ID is required", "INVALID_INPUT");
        }
        if (!EMPLOYEE_ID_PATTERN.matcher(employeeId.trim()).matches()) {
            throw new EmployeeServiceException("Invalid employee ID format. Expected: EMP followed by 3-6 digits", "INVALID_INPUT");
        }
    }

    public static void validateSalary(BigDecimal salary) throws EmployeeServiceException {
        if (salary == null) {
            throw new EmployeeServiceException("Salary is required", "INVALID_INPUT");
        }
        if (salary.compareTo(MIN_SALARY) < 0 || salary.compareTo(MAX_SALARY) > 0) {
            throw new EmployeeServiceException(
                    "Salary must be between " + MIN_SALARY + " and " + MAX_SALARY, "INVALID_SALARY");
        }
    }

    public static void validateRating(String rating) throws EmployeeServiceException {
        if (rating == null || rating.trim().isEmpty()) {
            throw new EmployeeServiceException("Performance rating is required", "INVALID_INPUT");
        }
        if (!VALID_RATINGS.contains(rating.trim().toUpperCase())) {
            throw new EmployeeServiceException(
                    "Invalid rating. Valid values: " + VALID_RATINGS, "INVALID_RATING");
        }
    }

    public static void validateTerminationReason(String reason) throws EmployeeServiceException {
        if (reason == null || reason.trim().isEmpty()) {
            throw new EmployeeServiceException("Termination reason is required", "INVALID_INPUT");
        }
        if (!VALID_TERMINATION_REASONS.contains(reason.trim().toUpperCase())) {
            throw new EmployeeServiceException(
                    "Invalid termination reason. Valid values: " + VALID_TERMINATION_REASONS, "INVALID_REASON");
        }
    }

    public static void validateNotes(String notes) throws EmployeeServiceException {
        if (notes != null && notes.length() > MAX_NOTES_LENGTH) {
            throw new EmployeeServiceException(
                    "Notes cannot exceed " + MAX_NOTES_LENGTH + " characters", "INVALID_INPUT");
        }
    }

    public static String sanitizeInput(String input) {
        if (input == null) return null;
        return input.trim()
                .replaceAll("[<>\"'&]", "")
                .replaceAll("\\s+", " ");
    }

    public static void validatePerformedBy(String performedBy) throws EmployeeServiceException {
        if (performedBy == null || performedBy.trim().isEmpty()) {
            throw new EmployeeServiceException("Performer identity is required", "INVALID_INPUT");
        }
        if (!EMPLOYEE_ID_PATTERN.matcher(performedBy.trim()).matches()) {
            throw new EmployeeServiceException("Invalid performer ID format", "INVALID_INPUT");
        }
    }
}

