package com.hr.security;

import com.hr.audit.AuditLogger;

import javax.xml.namespace.QName;
import javax.xml.soap.*;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;

public class AuthenticationHandler implements SOAPHandler<SOAPMessageContext> {

    private static final Logger logger = Logger.getLogger(AuthenticationHandler.class.getName());
    private static final String AUTH_NS = "http://hr.com/security";
    private static final Map<String, String> API_KEYS = new ConcurrentHashMap<>();
    private static final Map<String, List<String>> ROLE_PERMISSIONS = new ConcurrentHashMap<>();

    static {
        // In production, these would come from a secure credential store
        API_KEYS.put("hr-admin-key-2024", "HR_ADMIN");
        API_KEYS.put("hr-manager-key-2024", "HR_MANAGER");
        API_KEYS.put("hr-viewer-key-2024", "HR_VIEWER");

        ROLE_PERMISSIONS.put("HR_ADMIN", Arrays.asList(
                "updateSalary", "submitPerformanceReview", "terminateEmployee",
                "getEmployee", "getPerformanceHistory"));
        ROLE_PERMISSIONS.put("HR_MANAGER", Arrays.asList(
                "updateSalary", "submitPerformanceReview",
                "getEmployee", "getPerformanceHistory"));
        ROLE_PERMISSIONS.put("HR_VIEWER", Arrays.asList(
                "getEmployee", "getPerformanceHistory"));
    }

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(AUTH_NS, "AuthHeader"));
        return headers;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean isOutbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (isOutbound != null && isOutbound) {
            return true;
        }

        try {
            SOAPMessage message = context.getMessage();
            SOAPHeader header = message.getSOAPHeader();

            if (header == null) {
                AuditLogger.logSecurityEvent("AUTH_FAILURE", "No SOAP header present");
                generateSOAPFault(context, "Authentication required");
                return false;
            }

            String apiKey = null;
            Iterator<?> headerElements = header.getChildElements(new QName(AUTH_NS, "AuthHeader"));
            if (headerElements.hasNext()) {
                SOAPElement authHeader = (SOAPElement) headerElements.next();
                Iterator<?> apiKeyElements = authHeader.getChildElements(new QName(AUTH_NS, "ApiKey"));
                if (apiKeyElements.hasNext()) {
                    apiKey = ((SOAPElement) apiKeyElements.next()).getTextContent();
                }
            }

            if (apiKey == null || !API_KEYS.containsKey(apiKey)) {
                AuditLogger.logSecurityEvent("AUTH_FAILURE", "Invalid API key attempted");
                generateSOAPFault(context, "Invalid credentials");
                return false;
            }

            String role = API_KEYS.get(apiKey);
            context.put("userRole", role);
            context.setScope("userRole", MessageContext.Scope.APPLICATION);

            // Extract operation name for authorization
            SOAPBody body = message.getSOAPBody();
            if (body != null && body.getFirstChild() != null) {
                String operationName = body.getFirstChild().getLocalName();
                List<String> allowedOps = ROLE_PERMISSIONS.getOrDefault(role, Collections.emptyList());
                if (!allowedOps.contains(operationName)) {
                    AuditLogger.logSecurityEvent("AUTHZ_FAILURE",
                            "Role " + role + " not authorized for operation: " + operationName);
                    generateSOAPFault(context, "Not authorized for this operation");
                    return false;
                }
            }

            logger.info("Authenticated request with role: " + role);
            return true;

        } catch (SOAPException e) {
            logger.severe("Error processing SOAP security header: " + e.getMessage());
            return false;
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }

    private void generateSOAPFault(SOAPMessageContext context, String message) {
        try {
            SOAPMessage soapMessage = context.getMessage();
            SOAPBody body = soapMessage.getSOAPBody();
            body.removeContents();
            SOAPFault fault = body.addFault();
            fault.setFaultString(message);
            fault.setFaultCode(new QName("http://schemas.xmlsoap.org/soap/envelope/", "Client"));
        } catch (SOAPException e) {
            logger.severe("Error generating SOAP fault: " + e.getMessage());
        }
    }
}

