// ============================================

package com.hr.security;

import com.hr.audit.AuditLogger;

import javax.xml.namespace.QName;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import java.util.Collections;
import java.util.Map;
import java.util.Set;
import java.util.logging.Logger;

public class WsdlBlockingHandler implements SOAPHandler<SOAPMessageContext> {

    private static final Logger logger = Logger.getLogger(WsdlBlockingHandler.class.getName());

    @Override
    public Set<QName> getHeaders() {
        return Collections.emptySet();
    }

    @Override
    @SuppressWarnings("unchecked")
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean isOutbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (isOutbound != null && isOutbound) {
            return true;
        }

        // Block WSDL requests (HTTP GET with ?wsdl query parameter)
        String httpMethod = (String) context.get(MessageContext.HTTP_REQUEST_METHOD);
        if ("GET".equalsIgnoreCase(httpMethod)) {
            Map<String, Object> httpHeaders = (Map<String, Object>) context.get(MessageContext.HTTP_REQUEST_HEADERS);
            String queryString = (String) context.get(MessageContext.QUERY_STRING);

            if (queryString != null && queryString.toLowerCase().contains("wsdl")) {
                AuditLogger.logSecurityEvent("WSDL_ACCESS_BLOCKED",
                        "Attempted WSDL access blocked from external request");
                logger.warning("WSDL access attempt blocked");
                return false;
            }
        }

        return true;
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }
}

