// ============================================
// EmployeeServicePublisher.java - Service endpoint publisher
// ============================================

package com.hr.server;

import com.hr.service.EmployeeManagementServiceImpl;
import com.hr.security.ServiceHandlerResolver;
import com.sun.net.httpserver.HttpContext;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpServer;

import javax.xml.ws.Endpoint;
import java.net.InetSocketAddress;
import java.util.concurrent.Executors;
import java.util.logging.Logger;

public class EmployeeServicePublisher {

    private static final Logger logger = Logger.getLogger(EmployeeServicePublisher.class.getName());

    // Bind to internal interface only - prevents external access
    private static final String BIND_ADDRESS = "127.0.0.1";
    private static final int PORT = 8443;
    private static final String SERVICE_PATH = "/hr/employee-service";

    private Endpoint endpoint;
    private HttpServer httpServer;

    public void publish() throws Exception {
        logger.info("Starting HR Employee Management SOAP Service...");

        // Create HTTP server bound to internal interface only
        httpServer = HttpServer.create(new InetSocketAddress(BIND_ADDRESS, PORT), 0);
        httpServer.setExecutor(Executors.newFixedThreadPool(10));

        // Create and configure endpoint
        EmployeeManagementServiceImpl serviceImpl = new EmployeeManagementServiceImpl();
        endpoint = Endpoint.create(serviceImpl);

        // Disable WSDL publication by setting metadata to false
        // This is the primary mechanism to prevent WSDL information disclosure
        endpoint.setProperties(java.util.Collections.singletonMap(
                "javax.xml.ws.wsdl.description", (Object) null));

        // Create HTTP context
        HttpContext httpContext = httpServer.createContext(SERVICE_PATH);

        // Publish endpoint
        endpoint.publish(httpContext);

        // Wrap the default handler with our custom WSDL-blocking handler
        HttpHandler originalHandler = httpContext.getHandler();
        httpContext.setHandler(new CustomHttpHandler(originalHandler));

        // Start the server
        httpServer.start();

        String serviceUrl = "http://" + BIND_ADDRESS + ":" + PORT + SERVICE_PATH;
        logger.info("HR Employee Management Service published at: " + serviceUrl);
        logger.info("WSDL access is restricted to internal/whitelisted IPs only");
        logger.info("Service is bound to internal interface: " + BIND_ADDRESS);
    }

    public void stop() {
        logger.info("Stopping HR Employee Management Service...");
        if (endpoint != null) {
            endpoint.stop();
        }
        if (httpServer != null) {
            httpServer.stop(0);
        }
        logger.info("Service stopped.");
    }

    public static void main(String[] args) {
        EmployeeServicePublisher publisher = new EmployeeServicePublisher();
        try {
            publisher.publish();

            // Add shutdown hook for graceful shutdown
            Runtime.getRuntime().addShutdownHook(new Thread(() -> {
                logger.info("Shutdown hook triggered...");
                publisher.stop();
            }));

            logger.info("Service is running. Press Ctrl+C to stop.");

            // Keep the main thread alive
            Thread.currentThread().join();

        } catch (Exception e) {
            logger.severe("Failed to start service: " + e.getMessage());
            e.printStackTrace();
            publisher.stop();
            System.exit(1);
        }
    }
}

// ============================================
// EmployeeServiceClient.java - Test client
// ============================================

package com.hr.client;

import javax.xml.namespace.QName;
import javax.xml.soap.*;
import java.io.ByteArrayOutputStream;
import java.net.URL;
import java.util.logging.Logger;

/**
 * Test client demonstrating how to call the employee management service
 * with proper authentication headers.
 */
public class EmployeeServiceClient {

    private static final Logger logger = Logger.getLogger(EmployeeServiceClient.class.getName());
    private static final String SERVICE_URL = "http://127.0.0.1:8443/hr/employee-service";
    private static final String SERVICE_NS = "http://hr.com/employee/service";
    private static final String AUTH_NS = "http://hr.com/security";

    public static void main(String[] args) {
        try {
            // Test 1: Get Employee
            logger.info("=== Test 1: Get Employee ===");
            testGetEmployee("EMP001", "hr-admin-key-2024");

            // Test 2: Update Salary
            logger.info("\n=== Test 2: Update Salary ===");
            testUpdateSalary("EMP001", "90000.00", "Annual raise", "EMP003", "hr-admin-key-2024");

            // Test 3: Submit Performance Review
            logger.info("\n=== Test 3: Submit Performance Review ===");
            testSubmitPerformanceReview("EMP001", "EMP003", "EXCELLENT",
                    "Outstanding performance this quarter", "Q4-2024", "hr-manager-key-2024");

            // Test 4: Terminate Employee
            logger.info("\n=== Test 4: Terminate Employee ===");
            testTerminateEmployee("EMP005", "VOLUNTARY_RESIGNATION",
                    "Employee submitted resignation", "EMP003", "hr-admin-key-2024");

            // Test 5: Unauthorized access attempt
            logger.info("\n=== Test 5: Unauthorized Access (Viewer trying termination) ===");
            testTerminateEmployee("EMP002", "LAYOFF",
                    "Test unauthorized", "EMP003", "hr-viewer-key-2024");

            // Test 6: WSDL access attempt (should be blocked from external)
            logger.info("\n=== Test 6: WSDL Access Test ===");
            testWsdlAccess();

        } catch (Exception e) {
            logger.severe("Client error: " + e.getMessage());
            e.printStackTrace();
        }
    }

    private static void testGetEmployee(String employeeId, String apiKey) throws Exception {
        SOAPMessage request = createSOAPMessage("getEmployee", apiKey);
        SOAPBody body = request.getSOAPBody();
        SOAPElement operation = body.addChildElement("getEmployee", "ns", SERVICE_NS);
        operation.addChildElement("employeeId", "ns").addTextNode(employeeId);
        request.saveChanges();

        sendRequest(request);
    }

    private static void testUpdateSalary(String employeeId, String newSalary,
                                          String reason, String approvedBy, String apiKey) throws Exception {
        SOAPMessage request = createSOAPMessage("updateSalary", apiKey);
        SOAPBody body = request.getSOAPBody();
        SOAPElement operation = body.addChildElement("updateSalary", "ns", SERVICE_NS);
        operation.addChildElement("employeeId", "ns").addTextNode(employeeId);
        operation.addChildElement("newSalary", "ns").addTextNode(newSalary);
        operation.addChildElement("reason", "ns").addTextNode(reason);
        operation.addChildElement("approvedBy", "ns").addTextNode(approvedBy);
        request.saveChanges();

        sendRequest(request);
    }

    private static void testSubmitPerformanceReview(String employeeId, String reviewerId,
                                                     String rating, String notes,
                                                     String reviewPeriod, String apiKey) throws Exception {
        SOAPMessage request = createSOAPMessage("submitPerformanceReview", apiKey);
        SOAPBody body = request.getSOAPBody();
        SOAPElement operation = body.addChildElement("submitPerformanceReview", "ns", SERVICE_NS);
        operation.addChildElement("employeeId", "ns").addTextNode(employeeId);
        operation.addChildElement("reviewerId", "ns").addTextNode(reviewerId);
        operation.addChildElement("rating", "ns").addTextNode(rating);
        operation.addChildElement("notes", "ns").addTextNode(notes);
        operation.addChildElement("reviewPeriod", "ns").addTextNode(reviewPeriod);
        request.saveChanges();

        sendRequest(request);
    }

    private static void testTerminateEmployee(String employeeId, String reason,
                                               String notes, String processedBy, String apiKey) throws Exception {
        SOAPMessage request = createSOAPMessage("terminateEmployee", apiKey);
        SOAPBody body = request.getSOAPBody();
        SOAPElement operation = body.addChildElement("terminateEmployee", "ns", SERVICE_NS);
        operation.addChildElement("employeeId", "ns").addTextNode(employeeId);
        operation.addChildElement("reason", "ns").addTextNode(reason);
        operation.addChildElement("notes", "ns").addTextNode(notes);
        operation.addChildElement("processedBy", "ns").addTextNode(processedBy);
        request.saveChanges();

        sendRequest(request);
    }

    private static void testWsdlAccess() {
        try {
            URL wsdlUrl = new URL(SERVICE_URL + "?wsdl");
            java.net.HttpURLConnection conn = (java.net.HttpURLConnection) wsdlUrl.openConnection();
            conn.setRequestMethod("GET");
            int responseCode = conn.getResponseCode();
            logger.info("WSDL access response code: " + responseCode);
            if (responseCode == 403) {
                logger.info("WSDL access correctly blocked (403 Forbidden)");
            } else {
                logger.warning("WSDL access was not blocked - response code: " + responseCode);
            }
            conn.disconnect();
        } catch (Exception e) {
            logger.info("WSDL access result: " + e.getMessage());
        }
    }

    private static SOAPMessage createSOAPMessage(String operation, String apiKey) throws Exception {
        MessageFactory messageFactory = MessageFactory.newInstance();
        SOAPMessage message = messageFactory.createMessage();

        // Add authentication header
        SOAPHeader header = message.getSOAPHeader();
        SOAPElement authHeader = header.addChildElement("AuthHeader", "auth", AUTH_NS);
        authHeader.addChildElement("ApiKey", "auth").addTextNode(apiKey);

        return message;
    }

    private static void sendRequest(SOAPMessage request) throws Exception {
        // Log request
        ByteArrayOutputStream requestOut = new ByteArrayOutputStream();
        request.writeTo(requestOut);
        logger.info("Request:\n" + requestOut.toString());

        // Send request
        SOAPConnectionFactory connectionFactory = SOAPConnectionFactory.newInstance();
        SOAPConnection connection = connectionFactory.createConnection();

        try {
            SOAPMessage response = connection.call(request, SERVICE_URL);

            // Log response
            ByteArrayOutputStream responseOut = new ByteArrayOutputStream();
            response.writeTo(responseOut);
            logger.info("Response:\n" + responseOut.toString());

            // Check for fault
            if (response.getSOAPBody().hasFault()) {
                SOAPFault fault = response.getSOAPBody().getFault();
                logger.warning("SOAP Fault: " + fault.getFaultString());
            }
        } finally {
            connection.close();
        }
    }
}